import React, { useState, useMemo } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { ChevronLeft, Wallet, AlertCircle, CheckCircle2, Ticket, CalendarDays, Clock } from 'lucide-react';
import { useUser } from '../context/UserContext';
import { PlanType, Token } from '../types';

const TokenPurchasePage: React.FC = () => {
  const { planId } = useParams<{ planId: string }>();
  const navigate = useNavigate();
  const { user, updateBalance, addTokens, lotteryPlans } = useUser();

  const plan = useMemo(() => lotteryPlans.find(p => p.id === planId), [lotteryPlans, planId]);

  const [selectedTokens, setSelectedTokens] = useState<number[]>([]);
  const [showSuccess, setShowSuccess] = useState(false);

  const soldTokens = useMemo(() => [12, 45, 89, 110, 156, 199, 5, 23], []);

  if (!plan) {
    return (
      <div className="max-w-7xl mx-auto px-4 py-20 text-center">
        <div className="bg-white p-12 rounded-[3rem] border border-slate-100 shadow-sm inline-block">
          <AlertCircle size={64} className="text-amber-500 mx-auto mb-6" />
          <h2 className="text-2xl font-black text-slate-900 uppercase mb-4">Plan Not Found</h2>
          <p className="text-slate-500 mb-8 max-w-xs mx-auto">This lottery plan might have been removed or is currently unavailable.</p>
          <Link to="/lotteries" className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs">
            Back to Lotteries
          </Link>
        </div>
      </div>
    );
  }

  const toggleToken = (num: number) => {
    if (soldTokens.includes(num)) return;
    setSelectedTokens(prev => 
      prev.includes(num) ? prev.filter(t => t !== num) : [...prev, num]
    );
  };

  const totalCost = selectedTokens.length * plan.tokenPrice;
  const canAfford = user.walletBalance >= totalCost;

  const handlePurchase = () => {
    if (!canAfford) return;

    const newTokens: Token[] = selectedTokens.map(num => ({
      id: Math.random(),
      number: num,
      planId: plan.id,
      purchaseDate: new Date().toLocaleString(),
      drawDate: plan.drawTime,
      status: 'WAITING'
    }));

    updateBalance(-totalCost);
    addTokens(newTokens);
    setShowSuccess(true);

    setTimeout(() => {
      navigate('/my-tokens');
    }, 2000);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 md:py-12 bg-[#f8fafc] min-h-screen pb-24 animate-in fade-in duration-500">
      <Link to="/lotteries" className="inline-flex items-center text-indigo-600 font-black text-xs uppercase tracking-widest mb-8 hover:underline group">
        <ChevronLeft size={18} className="mr-1 group-hover:-translate-x-1 transition-transform" /> 
        Back to Lotteries
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* Left: Token Grid */}
        <div className="lg:col-span-8">
          <div className="bg-white rounded-[2.5rem] p-8 md:p-10 border border-slate-100 shadow-sm">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10">
              <div>
                 <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Select Lucky Numbers</h2>
                 <p className="text-xs font-medium text-slate-400 mt-1 uppercase tracking-widest">Aap is draw ke liye numbers choose karein.</p>
              </div>

              <div className="flex flex-wrap gap-4">
                <div className="flex items-center space-x-2">
                  <div className="w-4 h-4 bg-white border-2 border-slate-100 rounded-md"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Available</span>
                </div>
                <div className="flex items-center space-x-2">
                  <div className="w-4 h-4 bg-indigo-600 rounded-md"></div>
                  <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Selected</span>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-5 sm:grid-cols-8 md:grid-cols-10 gap-3">
              {Array.from({ length: plan.totalTokens }, (_, i) => i + 1).map((num) => {
                const isSold = soldTokens.includes(num);
                const isSelected = selectedTokens.includes(num);
                return (
                  <button
                    key={num}
                    disabled={isSold}
                    onClick={() => toggleToken(num)}
                    className={`aspect-square text-xs font-black rounded-xl transition-all border-2 flex items-center justify-center ${
                      isSold 
                        ? 'bg-slate-50 border-slate-100 text-slate-200 cursor-not-allowed'
                        : isSelected
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl shadow-indigo-600/20 scale-110 z-10'
                          : 'bg-white border-slate-50 text-slate-600 hover:border-indigo-400 hover:bg-slate-50 active:scale-90'
                    }`}
                  >
                    {isSold ? '✕' : num}
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        {/* Right: Summary */}
        <div className="lg:col-span-4">
          <div className="sticky top-24 space-y-6">
            <div className="bg-white rounded-[2.5rem] p-8 md:p-10 border border-slate-100 shadow-sm overflow-hidden relative group">
              <div className="absolute top-0 right-0 w-32 h-32 bg-slate-50 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 group-hover:bg-indigo-50 transition-colors"></div>

              <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                  <div className="text-6xl group-hover:scale-110 transition-transform duration-500 inline-block">{plan.icon}</div>
                  <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest text-white shadow-lg ${plan.drawCycle === 'WEEKLY' ? 'bg-indigo-600' : 'bg-pink-600'}`}>
                    {plan.drawCycle}
                  </span>
                </div>

                <h3 className="text-3xl font-black text-slate-900 uppercase mb-2 leading-none">{plan.name}</h3>
                <p className="text-xs font-medium text-slate-500 mb-8 uppercase tracking-widest border-b border-slate-50 pb-6">Checkout Summary</p>

                <div className="space-y-6">
                  <div className="flex justify-between items-center text-xs font-bold text-slate-400 uppercase tracking-widest">
                    <div className="flex items-center space-x-2">
                       <CalendarDays size={14} className="text-slate-300" />
                       <span>Cycle Type</span>
                    </div>
                    <span className="text-slate-900 font-black">{plan.drawCycle === 'WEEKLY' ? 'Weekly Draw' : 'Monthly Draw'}</span>
                  </div>

                  <div className="flex justify-between items-center text-xs font-bold text-slate-400 uppercase tracking-widest">
                    <div className="flex items-center space-x-2">
                       <Clock size={14} className="text-slate-300" />
                       <span>Draw Time</span>
                    </div>
                    <span className="text-slate-900 font-black">{plan.drawTime}</span>
                  </div>

                  <div className="flex justify-between items-center text-xs font-bold text-slate-400 uppercase tracking-widest border-t border-slate-50 pt-6">
                    <span>Selected ({selectedTokens.length})</span>
                    <span className="text-slate-900 font-black">PKR {(selectedTokens.length * plan.tokenPrice).toLocaleString()}</span>
                  </div>

                  <div className="flex justify-between items-end pt-4 border-t border-slate-50">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Bill</span>
                    <span className="text-4xl font-black text-indigo-600 leading-none">Rs {totalCost.toLocaleString()}</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-[#1a233a] rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden">
              <div className="relative z-10 space-y-8">
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-3">
                    <div className="p-3 bg-white/10 rounded-xl backdrop-blur-md">
                      <Wallet size={20} className="text-emerald-400" />
                    </div>
                    <div>
                       <span className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">My Balance</span>
                       <span className="font-black text-lg">Rs {user.walletBalance.toLocaleString()}</span>
                    </div>
                  </div>
                </div>

                {!canAfford && selectedTokens.length > 0 && (
                  <div className="flex items-start space-x-4 p-5 bg-red-500/10 rounded-[1.5rem] border border-red-500/20 animate-in fade-in slide-in-from-top-4">
                    <AlertCircle size={24} className="text-red-400 flex-shrink-0" />
                    <div className="space-y-2">
                      <p className="font-black text-[10px] text-red-400 uppercase tracking-widest">Insufficient Funds</p>
                      <Link to="/wallet" className="text-[10px] font-black text-white underline uppercase tracking-widest hover:text-emerald-400 block pt-1 transition-colors">Go to Deposit</Link>
                    </div>
                  </div>
                )}

                <button
                  onClick={handlePurchase}
                  disabled={selectedTokens.length === 0 || !canAfford || showSuccess}
                  className={`w-full py-6 rounded-3xl font-black uppercase tracking-[0.25em] text-xs transition-all flex items-center justify-center space-x-3 shadow-xl active:scale-95 ${
                    selectedTokens.length === 0 || !canAfford
                      ? 'bg-slate-700 text-slate-500 cursor-not-allowed'
                      : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-600/20'
                  }`}
                >
                  {showSuccess ? (
                    <>
                      <CheckCircle2 size={20} />
                      <span>ORDER PLACED!</span>
                    </>
                  ) : (
                    <>
                      <Ticket size={20} />
                      <span>Confirm Purchase</span>
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

