import React, { useState } from 'react';
import { Plus, Edit3, Trash2, Ticket, Trophy, Clock, PlayCircle, StopCircle, Eye, X, Share2, ToggleLeft, ToggleRight, CalendarDays, Calendar } from 'lucide-react';
import { useUser } from '../../context/UserContext.ts';
import { PlanType, LotteryPlan, DrawCycle } from '../../types.ts';

const AdminLottery: React.FC = () => {
  const { lotteryPlans, addLottery, deleteLottery, updateLottery } = useUser();
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);

  // New state for structured time picker
  const [drawHour, setDrawHour] = useState('04:00 PM');

  const [formData, setFormData] = useState<Partial<LotteryPlan>>({
    name: '',
    tokenPrice: 0,
    totalTokens: 200,
    totalWinners: 10,
    prizePerWinner: 0,
    drawTime: '',
    drawDay: 'Sunday',
    drawCycle: 'WEEKLY',
    icon: '🎟️',
    colorClass: 'text-indigo-600',
    bgClass: 'from-indigo-100 to-indigo-300',
    referralThreshold: 10,
    referralRewardCount: 1,
    isReferralEnabled: true
  });

  const handleOpenAdd = () => {
    setIsEditing(false);
    setFormData({
      name: '',
      tokenPrice: 0,
      totalTokens: 200,
      totalWinners: 10,
      prizePerWinner: 0,
      drawDay: 'Sunday',
      drawCycle: 'WEEKLY',
      icon: '🎟️',
      colorClass: 'text-indigo-600',
      bgClass: 'from-indigo-100 to-indigo-300',
      referralThreshold: 10,
      referralRewardCount: 1,
      isReferralEnabled: true
    });
    setDrawHour('04:00 PM');
    setShowModal(true);
  };

  const handleOpenEdit = (plan: LotteryPlan) => {
    setIsEditing(true);
    setFormData(plan);
    // Attempt to extract hour if it exists in the string
    const hourMatch = plan.drawTime.match(/\d{2}:\d{2}\s(?:AM|PM)/);
    if (hourMatch) setDrawHour(hourMatch[0]);
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Auto-generate the descriptive drawTime string based on cycle
    const finalDrawTime = formData.drawCycle === 'WEEKLY' 
      ? `Every ${formData.drawDay} at ${drawHour}` 
      : `Every ${formData.drawDay} of Month at ${drawHour}`;

    const submissionData = {
      ...formData,
      drawTime: finalDrawTime
    } as LotteryPlan;

    if (isEditing) {
      updateLottery(submissionData);
    } else {
      const newPlan: LotteryPlan = {
        ...submissionData,
