  PLATINUM = 'PLATINUM'
}

export type DrawCycle = 'WEEKLY' | 'MONTHLY';

export interface LotteryPlan {
  id: string;
  name: string;
  tokenPrice: number;
  totalTokens: number;
  totalWinners: number;
  prizePerWinner: number;
  drawTime: string; // Formatted display string
  drawDay: string;  // Stores 'Sunday' or '1st', '15th' etc.
  drawCycle: DrawCycle; 
  colorClass: string;
  bgClass: string;
  icon: string;
  image?: string;   // Base64 or URL for the lottery image
  // Referral System Props
  referralThreshold: number; 
  referralRewardCount: number; 
  isReferralEnabled: boolean; 
}

export interface Token {
  id: number;
  number: number;
  planId: string;
  purchaseDate: string;
  drawDate: string;
  status: 'WAITING' | 'WINNER' | 'NOT_SELECTED';
  prizeAmount?: number;
}

export interface Transaction {
  id: string;
  date: string;
  type: 'DEPOSIT' | 'WITHDRAWAL';
  amount: number;
  charges: number;
  netAmount: number;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  method: 'EasyPaisa' | 'JazzCash';
}

export interface User {
  id: string;
  firstName: string;
  lastName: string;
  username: string;
  email: string;
  mobile: string;
