import { createContext, useContext } from 'react';
import { User, Token, Transaction, LotteryPlan } from '../types';

export interface PaymentMethod {
  id: string;
  name: string;
  title: string;
  number: string;
  status: 'ACTIVE' | 'INACTIVE';
  type: string;
}

interface UserContextType {
  user: User;
  users: User[]; // All registered users for Admin
  isLoggedIn: boolean;
  tokens: Token[];
  transactions: Transaction[];
  lotteryPlans: LotteryPlan[];
  paymentMethods: PaymentMethod[];
  login: () => void;
  logout: () => void;
  addTokens: (tokens: Token[]) => void;
  updateBalance: (amount: number) => void;
  addTransaction: (tx: Transaction) => void;
  updateTransactionStatus: (id: string, status: 'APPROVED' | 'REJECTED') => void;
  addLottery: (plan: LotteryPlan) => void;
  updateLottery: (plan: LotteryPlan) => void;
  deleteLottery: (id: string) => void;
  addPaymentMethod: (method: PaymentMethod) => void;
  updatePaymentMethod: (method: PaymentMethod) => void;
  deletePaymentMethod: (id: string) => void;
}

export const UserContext = createContext<UserContextType | undefined>(undefined);

export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) throw new Error('useUser must be used within UserProvider');
  return context;
};

