import React, { useMemo, useState, useEffect } from 'react';
import { Users, CreditCard, ArrowDownCircle, ArrowUpCircle, Ticket, BarChart3, Clock, TrendingUp, AlertCircle, Zap, Activity } from 'lucide-react';
import { useUser } from '../../context/UserContext.ts';

const AdminDashboard: React.FC = () => {
  const { users, transactions, tokens } = useUser();

  // Fake "Active Now" counter that fluctuates slightly for real-time feel
  const [activeNow, setActiveNow] = useState(Math.floor(users.length * 0.4) + 1);

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveNow(prev => {
        const change = Math.random() > 0.5 ? 1 : -1;
        const newVal = prev + change;
        return newVal < 1 ? 1 : newVal > users.length ? users.length : newVal;
      });
    }, 4000);
    return () => clearInterval(interval);
  }, [users.length]);

  const stats = useMemo(() => {
    // ACCURATE REAL-TIME TRANSACTION CALCULATIONS
    const pendingDeposits = transactions.filter(t => t.type === 'DEPOSIT' && t.status === 'PENDING').length;
    const pendingWithdrawals = transactions.filter(t => t.type === 'WITHDRAWAL' && t.status === 'PENDING').length;

    // Total Revenue is based on APPROVED deposits
    const approvedDepositsTotal = transactions
      .filter(t => t.type === 'DEPOSIT' && t.status === 'APPROVED')
      .reduce((acc, curr) => acc + curr.amount, 0);

    // Total Payouts is based on APPROVED withdrawals
    const approvedWithdrawalsTotal = transactions
      .filter(t => t.type === 'WITHDRAWAL' && t.status === 'APPROVED')
      .reduce((acc, curr) => acc + curr.amount, 0);

    return [
      { 
        label: 'Pending Deposits', 
        value: pendingDeposits.toString(), 
        icon: <ArrowDownCircle size={24} />, 
        color: 'bg-amber-500', 
        sub: 'Review Proofs', 
        isLive: pendingDeposits > 0 
      },
      { 
        label: 'Pending Payouts', 
        value: pendingWithdrawals.toString(), 
        icon: <ArrowUpCircle size={24} />, 
        color: 'bg-indigo-600', 
        sub: 'Awaiting Payout', 
        isLive: pendingWithdrawals > 0 
      },
      { 
        label: 'Tokens Sold', 
        value: tokens.length.toString(), 
        icon: <Ticket size={24} />, 
        color: 'bg-emerald-600', 
        sub: 'User Purchases',
        isLive: true
      },
      { 
        label: 'Total Money In', 
        value: `Rs ${approvedDepositsTotal.toLocaleString()}`, 
        icon: <Activity size={24} />, 
        color: 'bg-emerald-700', 
        sub: 'Verified Deposits' 
      },
      { 
        label: 'Total Payouts', 
        value: `Rs ${approvedWithdrawalsTotal.toLocaleString()}`, 
        icon: <CreditCard size={24} />, 
        color: 'bg-slate-900', 
        sub: 'Verified Payouts' 
      },
      { 
        label: 'Total Users', 
        value: users.length.toString(), 
        icon: <Users size={24} />, 
        color: 'bg-blue-600', 
        sub: 'Registered Base' 
      },
    ];
  }, [users.length, transactions, tokens.length]);

  const recentActivities = useMemo(() => {
    const txActivity = transactions.slice(0, 10).map(t => ({
      id: t.id,
      user: t.username || 'System',
      desc: `${t.type} ${t.status}: Rs ${t.amount}`,
      time: t.date.split(',')[1] || t.date,
      icon: t.type === 'DEPOSIT' ? '💰' : '💸',
      color: t.status === 'PENDING' ? 'text-amber-500' : 'text-emerald-500'
    }));

    const tokenActivity = tokens.slice(0, 5).map(tk => ({
      id: tk.id.toString(),
      user: 'New Purchase',
      desc: `Ticket #${tk.number} (${tk.planId})`,
      time: tk.purchaseDate.split(',')[1] || tk.purchaseDate,
      icon: '🎫',
      color: 'text-indigo-500'
    }));

    return [...txActivity, ...tokenActivity].sort((a, b) => b.id.localeCompare(a.id)).slice(0, 12);
  }, [transactions, tokens]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tight">Live Dashboard</h1>
          <p className="text-slate-500 font-medium">Tracking all financial flows and token activity in real-time.</p>
        </div>
        <div className="flex items-center space-x-2 bg-white px-4 py-2 rounded-xl border border-slate-200 text-[10px] font-black uppercase tracking-widest text-slate-400 shadow-sm">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></div>
          <span>Systems Online & Syncing</span>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-4 md:gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white rounded-[2rem] p-5 md:p-6 border border-slate-100 shadow-sm group hover:shadow-xl hover:-translate-y-1 transition-all duration-300 relative overflow-hidden">
             <div className={`${stat.color} w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center text-white mb-4 shadow-lg shadow-${stat.color.split('-')[1]}-600/20`}>
                {stat.icon}
             </div>
             <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
             <h3 className="text-lg md:text-xl font-black text-slate-900 truncate">{stat.value}</h3>
             <div className="mt-3 flex items-center space-x-1 text-[8px] font-black uppercase text-slate-400">
                <AlertCircle size={10} className={stat.isLive ? "text-indigo-500" : "text-slate-300"} />
                <span>{stat.sub}</span>
             </div>
             {stat.isLive && (
               <div className="absolute top-4 right-4 flex items-center space-x-1">
                 <span className="w-1.5 h-1.5 bg-red-500 rounded-full animate-pulse"></span>
                 <span className="text-[7px] font-black text-red-500 uppercase tracking-tighter">New Action</span>
               </div>
             )}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-5 flex flex-col space-y-4">
          <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col h-full overflow-hidden">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-900 uppercase tracking-tight text-sm">Real-time Stream</h3>
              <div className="flex items-center space-x-2 px-3 py-1 bg-white border border-slate-100 rounded-full">
                <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-pulse"></div>
                <span className="text-[8px] font-black text-indigo-500 uppercase tracking-widest">Active Tracking</span>
              </div>
            </div>
            <div className="p-8 space-y-6 overflow-y-auto max-h-[600px] custom-scrollbar">
              {recentActivities.map((act, i) => (
                <div key={act.id + i} className="flex items-start space-x-4 group animate-in slide-in-from-left duration-300" style={{ animationDelay: `${i * 30}ms` }}>
                  <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-lg shadow-inner group-hover:scale-110 transition-transform flex-shrink-0">
                    {act.icon}
                  </div>
                  <div className="flex-grow border-b border-slate-50 pb-4">
                    <p className={`text-[11px] font-black uppercase leading-tight mb-1 ${act.color}`}>
                      {act.user} <span className="text-slate-500 font-bold lowercase">— {act.desc}</span>
                    </p>
                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center">
                       <Clock size={10} className="mr-1" />
                       {act.time}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="lg:col-span-7">
          <div className="bg-[#1a233a] rounded-[2.5rem] p-10 text-white h-full relative overflow-hidden shadow-2xl">
            <div className="relative z-10 flex flex-col h-full">
              <div className="flex justify-between items-start mb-12">
                <div>
                  <h3 className="text-2xl font-black uppercase tracking-tight">System Financial Status</h3>
                  <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.2em] mt-2">Overall platform circulation</p>
                </div>
                <TrendingUp size={32} className="text-indigo-400" />
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 gap-8 mb-auto">
                 <div className="space-y-1">
                    <span className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Payout Efficiency</span>
                    <span className="text-3xl font-black text-amber-400">&lt; 12h</span>
                 </div>
                 <div className="space-y-1">
                    <span className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Live Members</span>
                    <span className="text-3xl font-black text-indigo-400">{activeNow}</span>
                 </div>
                 <div className="space-y-1">
                    <span className="block text-[9px] font-black text-slate-400 uppercase tracking-widest">Verified Inflow</span>
                    <span className="text-3xl font-black text-emerald-400">100%</span>
                 </div>
              </div>

              <div className="mt-12 pt-12 border-t border-white/5">
                 <div className="p-6 bg-white/5 rounded-3xl border border-white/10 flex items-center justify-between shadow-inner">
                    <div>
                       <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Action Required</span>
                       <p className="text-xs font-bold text-white mt-1">
                         Review {transactions.filter(t => t.status === 'PENDING').length} pending requests across your dashboard.
                       </p>
                    </div>
                    <AlertCircle className="text-amber-500" size={24} />
                 </div>
              </div>
            </div>
            <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-600/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

