                />
             </div>

             <button className="p-2.5 text-slate-400 hover:bg-slate-50 rounded-xl transition-all relative">
                <Bell size={20} />
                {(pendingDeposits + pendingWithdrawals) > 0 && (
                   <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white animate-ping"></span>
                )}
             </button>

             <div className="h-8 w-px bg-slate-200 mx-2"></div>

             <div className="flex items-center space-x-3">
                <div className="text-right hidden sm:block">
                   <p className="text-xs font-black text-slate-900 leading-none">Admin Panel</p>
                   <p className="text-[10px] text-emerald-500 font-bold uppercase mt-1">Super Admin</p>
