                <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400 border border-slate-200">
                   <Users size={20} />
                </div>
             </div>
          </div>
        </header>

        {/* PAGE CONTENT */}
        <main className="p-6 md:p-10">
          <Outlet />
        </main>
      </div>
