import React, { useMemo, useState, useEffect } from 'react';
import { Users, CreditCard, ArrowDownCircle, ArrowUpCircle, Ticket, BarChart3, Clock, TrendingUp, AlertCircle, Zap, Activity } from 'lucide-react';
import { useUser } from '../../context/UserContext.ts';

const AdminDashboard: React.FC = () => {
  const { users, transactions, tokens } = useUser();
  const [activeNow, setActiveNow] = useState(Math.floor(users.length * 0.4) + 1);

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveNow(prev => {
        const change = Math.random() > 0.5 ? 1 : -1;
        const newVal = prev + change;
        return newVal < 1 ? 1 : newVal > users.length ? users.length : newVal;
      });
    }, 4000);
    return () => clearInterval(interval);
  }, [users.length]);

  const stats = useMemo(() => {
    const pendingDeposits = transactions.filter(t => t.type === 'DEPOSIT' && t.status === 'PENDING').length;
    const pendingWithdrawals = transactions.filter(t => t.type === 'WITHDRAWAL' && t.status === 'PENDING').length;
    const approvedDepositsTotal = transactions.filter(t => t.type === 'DEPOSIT' && t.status === 'APPROVED').reduce((acc, curr) => acc + curr.amount, 0);
    const approvedWithdrawalsTotal = transactions.filter(t => t.type === 'WITHDRAWAL' && t.status === 'APPROVED').reduce((acc, curr) => acc + curr.amount, 0);

    return [
      { label: 'Pending Deposits', value: pendingDeposits.toString(), icon: <ArrowDownCircle size={20} />, color: 'bg-amber-500', sub: 'Review Proofs', isLive: pendingDeposits > 0 },
      { label: 'Pending Payouts', value: pendingWithdrawals.toString(), icon: <ArrowUpCircle size={20} />, color: 'bg-indigo-600', sub: 'Awaiting Payout', isLive: pendingWithdrawals > 0 },
      { label: 'Tokens Sold', value: tokens.length.toString(), icon: <Ticket size={20} />, color: 'bg-emerald-600', sub: 'Purchases', isLive: true },
      { label: 'Total Money In', value: `Rs ${approvedDepositsTotal.toLocaleString()}`, icon: <Activity size={20} />, color: 'bg-emerald-700', sub: 'Verified' },
      { label: 'Total Payouts', value: `Rs ${approvedWithdrawalsTotal.toLocaleString()}`, icon: <CreditCard size={20} />, color: 'bg-slate-900', sub: 'Processed' },
      { label: 'Total Users', value: users.length.toString(), icon: <Users size={20} />, color: 'bg-blue-600', sub: 'Registered' },
    ];
  }, [users.length, transactions, tokens.length]);

  const recentActivities = useMemo(() => {
    const txActivity = transactions.slice(0, 10).map(t => ({
      id: t.id, user: t.username || 'System', desc: `${t.type}: Rs ${t.amount}`, time: t.date.split(',')[1] || t.date,
      icon: t.type === 'DEPOSIT' ? '💰' : '💸', color: t.status === 'PENDING' ? 'text-amber-500' : 'text-emerald-500'
    }));
    const tokenActivity = tokens.slice(0, 5).map(tk => ({
      id: tk.id.toString(), user: 'Ticket', desc: `#${tk.number} (${tk.planId})`, time: tk.purchaseDate.split(',')[1] || tk.purchaseDate,
      icon: '🎫', color: 'text-indigo-500'
    }));
    return [...txActivity, ...tokenActivity].sort((a, b) => b.id.localeCompare(a.id)).slice(0, 8);
  }, [transactions, tokens]);

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-black text-slate-900 uppercase tracking-tight">Live Dashboard</h1>
          <p className="text-xs md:text-sm text-slate-500 font-medium tracking-wide">Financial flows & token activity monitoring.</p>
        </div>
        <div className="flex items-center space-x-2 bg-white px-3 py-1.5 rounded-xl border border-slate-200 text-[9px] font-black uppercase tracking-widest text-slate-400 shadow-sm">
          <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping"></div>
          <span>Systems Live</span>
        </div>
      </div>

      {/* Responsive Stats Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3 md:gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white rounded-[1.5rem] md:rounded-[2rem] p-4 md:p-6 border border-slate-100 shadow-sm group hover:shadow-lg transition-all relative overflow-hidden">
             <div className={`${stat.color} w-8 h-8 md:w-10 md:h-10 rounded-xl flex items-center justify-center text-white mb-3 md:mb-4 shadow-lg`}>
                {stat.icon}
             </div>
             <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1 truncate">{stat.label}</p>
             <h3 className="text-base md:text-lg font-black text-slate-900 truncate">{stat.value}</h3>
             {stat.isLive && <span className="absolute top-3 right-3 w-1.5 h-1.5 bg-red-500 rounded-full animate-pulse"></span>}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
        {/* Activity Feed */}
        <div className="lg:col-span-5 flex flex-col">
          <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm flex flex-col h-full overflow-hidden">
            <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
              <h3 className="font-black text-slate-900 uppercase tracking-tight text-xs">Recent Activity</h3>
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-pulse"></div>
            </div>
            <div className="p-6 space-y-4 overflow-y-auto max-h-[400px]">
              {recentActivities.map((act, i) => (
                <div key={i} className="flex items-start space-x-3 group border-b border-slate-50 pb-3 last:border-0">
                  <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-sm flex-shrink-0">
                    {act.icon}
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className={`text-[10px] font-black uppercase truncate ${act.color}`}>
                      {act.user} <span className="text-slate-500 font-bold lowercase">— {act.desc}</span>
                    </p>
                    <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{act.time}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* System Status / Summary */}
        <div className="lg:col-span-7">
          <div className="bg-[#1a233a] rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-10 text-white h-full relative overflow-hidden shadow-2xl">
            <div className="relative z-10 space-y-8">
              <div className="flex justify-between items-start">
