  ]);

  const [isLoggedIn, setIsLoggedIn] = useState(true);
  const [tokens, setTokens] = useState<Token[]>([]);
  const [lotteryPlans, setLotteryPlans] = useState<LotteryPlan[]>(LOTTERY_PLANS);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([
    { id: '1', name: 'EasyPaisa', title: 'Dilbar Ali', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' },
    { id: '2', name: 'JazzCash', title: 'Dilbar Ali', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' }
  ]);
  const [transactions, setTransactions] = useState<Transaction[]>([
    {
      id: 'tx_initial_1',
      date: new Date().toLocaleString(),
      type: 'DEPOSIT',
      amount: 1000,
      charges: 100,
      netAmount: 900,
      status: 'APPROVED',
      method: 'EasyPaisa',
      username: 'dilbar_lucky'
    }
  ]);

  const addTokens = (newTokens: Token[]) => setTokens(prev => [...prev, ...newTokens]);
  const updateBalance = (amount: number) => setUser(prev => ({ ...prev, walletBalance: prev.walletBalance + amount }));

  const updateUserBalance = (userId: string, amount: number) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) return { ...u, walletBalance: u.walletBalance + amount };
      return u;
    }));
    if (user.id === userId) {
      updateBalance(amount);
    }
  };

  const addTransaction = (tx: Transaction) => setTransactions(prev => [tx, ...prev]);

  const updateTransactionStatus = (id: string, status: 'APPROVED' | 'REJECTED') => {
    setTransactions(prev => prev.map(tx => {
      if (tx.id === id) {
        if (status === 'APPROVED' && tx.status === 'PENDING') {
          const targetUser = users.find(u => u.username === tx.username);
          if (targetUser) {
             if (tx.type === 'DEPOSIT') updateUserBalance(targetUser.id, tx.netAmount);
          }
        }
        if (tx.type === 'WITHDRAWAL' && status === 'REJECTED' && tx.status === 'PENDING') {
           const targetUser = users.find(u => u.username === tx.username);
           if (targetUser) updateUserBalance(targetUser.id, tx.amount);
        }
        return { ...tx, status };
      }
      return tx;
    }));
  };

  const addLottery = (plan: LotteryPlan) => setLotteryPlans(prev => [...prev, plan]);
  const updateLottery = (plan: LotteryPlan) => setLotteryPlans(prev => prev.map(p => p.id === plan.id ? plan : p));
  const deleteLottery = (id: string) => setLotteryPlans(prev => prev.filter(p => p.id !== id));

  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => prev.map(m => m.id === method.id ? method : m));
  const deletePaymentMethod = (id: string) => setPaymentMethods(prev => prev.filter(m => m.id !== id));

  return (
    <UserContext.Provider value={{ 
      user, 
      users,
      isLoggedIn, 
      tokens, 
      transactions,
      lotteryPlans,
      paymentMethods,
      login: () => setIsLoggedIn(true),
      logout: () => setIsLoggedIn(false),
      addTokens,
      updateBalance,
      updateUserBalance,
      addTransaction,
      updateTransactionStatus,
      addLottery,
      updateLottery,
      deleteLottery,
      addPaymentMethod,
      updatePaymentMethod,
      deletePaymentMethod
    }}>
      <Router>
        <AppContent />
      </Router>
    </UserContext.Provider>
  );
};

export default App;

