const App: React.FC = () => {
  const [user, setUser] = useState<User>({ 
    ...MOCK_USER, 
    role: 'USER', 
    password: 'password123', 
    joinDate: '2024-01-10',
    walletBalance: 0 
  });

  const [users, setUsers] = useState<User[]>([
    { ...MOCK_USER, id: '1', role: 'USER', password: 'password123', joinDate: '2024-01-10', walletBalance: 0 }, 
    { ...MOCK_USER, id: '2', role: 'ADMIN', firstName: 'Admin', lastName: 'Support', username: 'admin_boss', mobile: '03001112223', password: 'admin_pass_123', joinDate: '2024-02-05', walletBalance: 50000, referralsCount: 0 },
    { ...MOCK_USER, id: '3', role: 'USER', firstName: 'Sara', lastName: 'Khan', username: 'sara_win', mobile: '03459876543', password: 'sara_secure_7', joinDate: '2024-01-15', walletBalance: 12000, referralsCount: 25 },
  ]);

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [tokens, setTokens] = useState<Token[]>([]);
  const [lotteryPlans, setLotteryPlans] = useState<LotteryPlan[]>(LOTTERY_PLANS);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([
    { id: '1', name: 'EasyPaisa', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' },
    { id: '2', name: 'JazzCash', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' }
  ]);
  const [transactions, setTransactions] = useState<Transaction[]>([
    {
      id: 'tx_initial_1',
      date: new Date().toLocaleString(),
      type: 'DEPOSIT',
      amount: 1000,
      charges: 100,
      netAmount: 900,
      status: 'APPROVED',
      method: 'EasyPaisa',
      username: 'premium_member'
    }
  ]);

  const login = (username?: string, password?: string) => {
    const foundUser = users.find(u => u.username === username && u.password === password);
    if (foundUser) {
      setUser(foundUser);
      setIsLoggedIn(true);
      return true;
    }
    return false;
  };

  const signUp = (userData: Partial<User>) => {
    // Check if username already exists
    if (users.some(u => u.username === userData.username)) {
      alert("Username already taken!");
      return false;
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      firstName: userData.firstName || '',
      lastName: userData.lastName || '',
      username: userData.username || '',
      email: userData.email || '',
      mobile: userData.mobile || '',
      password: userData.password || '',
      role: 'USER',
      walletBalance: 0,
      referralCode: 'LUCKY' + Math.floor(1000 + Math.random() * 9000),
      referralsCount: 0,
      activeReferrals: 0,
      totalWinnings: 0,
      planReferralStats: {},
      joinDate: new Date().toLocaleDateString()
    };

    setUsers(prev => [...prev, newUser]);
    setUser(newUser);
    setIsLoggedIn(true);
    return true;
  };

  const logout = () => {
    setIsLoggedIn(false);
    setUser({ ...MOCK_USER, role: 'USER', walletBalance: 0 });
    setTokens([]);
  };

  const deleteAccount = (userId: string) => {
    setUsers(prev => prev.filter(u => u.id !== userId));
    if (user.id === userId) {
      logout();
    }
  };

  const addTokens = (newTokens: Token[]) => setTokens(prev => [...prev, ...newTokens]);
  const updateBalance = (amount: number) => setUser(prev => ({ ...prev, walletBalance: prev.walletBalance + amount }));

  const updateUserBalance = (userId: string, amount: number) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) return { ...u, walletBalance: u.walletBalance + amount };
      return u;
    }));
    if (user.id === userId) {
      updateBalance(amount);
    }
  };

  const addTransaction = (tx: Transaction) => setTransactions(prev => [tx, ...prev]);

  const updateTransactionStatus = (id: string, status: 'APPROVED' | 'REJECTED') => {
    setTransactions(prev => prev.map(tx => {
      if (tx.id === id) {
        if (status === 'APPROVED' && tx.status === 'PENDING') {
          const targetUser = users.find(u => u.username === tx.username);
          if (targetUser) {
             if (tx.type === 'DEPOSIT') updateUserBalance(targetUser.id, tx.netAmount);
          }
        }
        return { ...tx, status };
      }
      return tx;
    }));
  };

  const addLottery = (plan: LotteryPlan) => setLotteryPlans(prev => [...prev, plan]);
  const updateLottery = (plan: LotteryPlan) => setLotteryPlans(prev => prev.map(p => p.id === plan.id ? plan : p));
  const deleteLottery = (id: string) => setLotteryPlans(prev => prev.filter(p => p.id !== id));

  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => prev.map(m => m.id === method.id ? method : m));
  const deletePaymentMethod = (id: string) => setPaymentMethods(prev => prev.filter(m => m.id !== id));

  return (
    <UserContext.Provider value={{ 
      user, 
      users,
      isLoggedIn, 
      tokens, 
      transactions,
      lotteryPlans,
      paymentMethods,
      login,
      signUp,
      logout,
      deleteAccount,
      addTokens,
      updateBalance,
      updateUserBalance,
      addTransaction,
      updateTransactionStatus,
      addLottery,
      updateLottery,
      deleteLottery,
      addPaymentMethod,
      updatePaymentMethod,
      deletePaymentMethod
    }}>
      <Router>
        <AppContent />
      </Router>
    </UserContext.Provider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Mail, Lock, Eye, EyeOff, User as UserIcon, Phone, Share2, ArrowRight, Star, Sparkles, UserCircle } from 'lucide-react';
import { useUser } from '../context/UserContext';

const SignUpPage: React.FC = () => {
  const [showPassword, setShowPassword] = useState(false);
  const location = useLocation();
  const { signUp } = useUser();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    username: '',
    email: '',
    mobile: '',
    password: '',
    confirmPassword: '',
    refCode: ''
  });

  // Detect referral code from URL ?ref=CODE
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const ref = params.get('ref');
    if (ref) {
      setFormData(prev => ({ ...prev, refCode: ref }));
    }
  }, [location]);

  const handleSignUp = (e: React.FormEvent) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      alert("Passwords do not match!");
      return;
    }

    if (formData.password.length < 6) {
      alert("Password must be at least 6 characters!");
      return;
    }

    const success = signUp({
      firstName: formData.firstName,
      lastName: formData.lastName,
      username: formData.username,
      email: formData.email,
      mobile: formData.mobile,
      password: formData.password
    });

    if (success) {
      // New users have 0 balance, redirect to wallet for onboarding
      navigate('/wallet');
    }
  };

  return (
