  });

  const [tokens, setTokens] = useState<Token[]>(() => getStoredData('lucky_tokens', []));

  const [lotteryPlans, setLotteryPlans] = useState<LotteryPlan[]>(() => getStoredData('lucky_plans', LOTTERY_PLANS));

  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>(() => getStoredData('lucky_payments', [
    { id: '1', name: 'EasyPaisa', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' },
    { id: '2', name: 'JazzCash', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' }
  ]));

  const [transactions, setTransactions] = useState<Transaction[]>(() => getStoredData('lucky_transactions', []));

  // --- PERSISTENCE SYNC ---
  useEffect(() => {
    localStorage.setItem('lucky_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('lucky_isLoggedIn', JSON.stringify(isLoggedIn));
  }, [isLoggedIn]);

  useEffect(() => {
    localStorage.setItem('lucky_currentUser', JSON.stringify(user));
    // Sync current logged in user back to users array if logged in
    if (isLoggedIn) {
      setUsers(prev => prev.map(u => u.id === user.id ? user : u));
    }
  }, [user, isLoggedIn]);

  useEffect(() => {
    localStorage.setItem('lucky_tokens', JSON.stringify(tokens));
  }, [tokens]);

  useEffect(() => {
    localStorage.setItem('lucky_plans', JSON.stringify(lotteryPlans));
  }, [lotteryPlans]);

  useEffect(() => {
    localStorage.setItem('lucky_payments', JSON.stringify(paymentMethods));
  }, [paymentMethods]);

  useEffect(() => {
    localStorage.setItem('lucky_transactions', JSON.stringify(transactions));
  }, [transactions]);

  // --- AUTH LOGIC ---
  const login = (username?: string, password?: string) => {
    const foundUser = users.find(u => u.username === username && u.password === password);
    if (foundUser) {
      setUser(foundUser);
      setIsLoggedIn(true);
      return true;
    }
    return false;
  };

  const signUp = (userData: Partial<User>) => {
    if (users.some(u => u.username === userData.username)) {
      alert("Username already taken!");
      return false;
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      firstName: userData.firstName || '',
      lastName: userData.lastName || '',
      username: userData.username || '',
      email: userData.email || '',
      mobile: userData.mobile || '',
      password: userData.password || '',
      role: 'USER',
      walletBalance: 0,
      referralCode: 'LUCKY' + Math.floor(1000 + Math.random() * 9000),
      referralsCount: 0,
      activeReferrals: 0,
      totalWinnings: 0,
      planReferralStats: {},
      joinDate: new Date().toLocaleDateString()
    };

    setUsers(prev => [...prev, newUser]);
    setUser(newUser);
    setIsLoggedIn(true);
    return true;
  };

  const logout = () => {
    setIsLoggedIn(false);
    setUser({ ...MOCK_USER, role: 'USER', walletBalance: 0 });
    // Note: We don't clear tokens globally, only current user's session ends
  };

  const deleteAccount = (userId: string) => {
    setUsers(prev => prev.filter(u => u.id !== userId));
    if (user.id === userId) {
      logout();
    }
  };

  // --- STATE UPDATERS ---
  const addTokens = (newTokens: Token[]) => setTokens(prev => [...prev, ...newTokens]);

  const updateBalance = (amount: number) => {
    setUser(prev => ({ ...prev, walletBalance: prev.walletBalance + amount }));
  };

  const updateUserBalance = (userId: string, amount: number) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) {
        const updated = { ...u, walletBalance: u.walletBalance + amount };
        if (isLoggedIn && user.id === userId) setUser(updated);
        return updated;
      }
      return u;
    }));
  };

  const addTransaction = (tx: Transaction) => setTransactions(prev => [tx, ...prev]);

  const updateTransactionStatus = (id: string, status: 'APPROVED' | 'REJECTED') => {
    setTransactions(prev => prev.map(tx => {
      if (tx.id === id) {
        if (status === 'APPROVED' && tx.status === 'PENDING') {
          const targetUser = users.find(u => u.username === tx.username);
          if (targetUser) {
             updateUserBalance(targetUser.id, tx.netAmount);
          }
        }
        return { ...tx, status };
      }
      return tx;
    }));
  };

  const addLottery = (plan: LotteryPlan) => setLotteryPlans(prev => [...prev, plan]);
  const updateLottery = (plan: LotteryPlan) => setLotteryPlans(prev => prev.map(p => p.id === plan.id ? plan : p));
  const deleteLottery = (id: string) => setLotteryPlans(prev => prev.filter(p => p.id !== id));

  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => prev.map(m => m.id === method.id ? method : m));
  const deletePaymentMethod = (id: string) => setPaymentMethods(prev => prev.filter(m => m.id !== id));

  return (
    <UserContext.Provider value={{ 
      user, 
      users,
      isLoggedIn, 
      tokens, 
      transactions,
      lotteryPlans,
      paymentMethods,
      login,
      signUp,
      logout,
      deleteAccount,
      addTokens,
      updateBalance,
      updateUserBalance,
      addTransaction,
      updateTransactionStatus,
      addLottery,
      updateLottery,
      deleteLottery,
      addPaymentMethod,
      updatePaymentMethod,
      deletePaymentMethod
    }}>
      <Router>
        <AppContent />
      </Router>
    </UserContext.Provider>
  );
};

export default App;

