    { id: '2', name: 'JazzCash', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' }
  ]));
  const [transactions, setTransactions] = useState<Transaction[]>(() => getStoredData('lucky_transactions', []));
  const [whatsappContact, setWhatsappContact] = useState<string>(() => getStoredData('lucky_whatsapp', '923177730425'));

  // REAL-TIME PERSISTENCE
  useEffect(() => { localStorage.setItem('lucky_users', JSON.stringify(users)); }, [users]);
  useEffect(() => { localStorage.setItem('lucky_isLoggedIn', JSON.stringify(isLoggedIn)); }, [isLoggedIn]);
  useEffect(() => {
    if (user && user.id) {
      localStorage.setItem('lucky_currentUser', JSON.stringify(user));
      setUsers(prev => prev.map(u => u.id === user.id ? user : u));
    }
  }, [user]);
  useEffect(() => { localStorage.setItem('lucky_tokens', JSON.stringify(tokens)); }, [tokens]);
  useEffect(() => { localStorage.setItem('lucky_plans', JSON.stringify(lotteryPlans)); }, [lotteryPlans]);
  useEffect(() => { localStorage.setItem('lucky_payments', JSON.stringify(paymentMethods)); }, [paymentMethods]);
  useEffect(() => { localStorage.setItem('lucky_transactions', JSON.stringify(transactions)); }, [transactions]);
  useEffect(() => { localStorage.setItem('lucky_whatsapp', JSON.stringify(whatsappContact)); }, [whatsappContact]);

  const login = (username?: string, password?: string) => {
    const foundUser = users.find(u => u.username === username && u.password === password);
    if (foundUser) {
      setUser(foundUser);
      setIsLoggedIn(true);
      return true;
    }
    return false;
  };

  const signUp = (userData: Partial<User>) => {
    // REAL DATA VALIDATION
    if (users.some(u => u.username === userData.username)) {
      alert("Username already taken! Please choose another.");
      return false;
    }
    if (users.some(u => u.mobile === userData.mobile)) {
      alert("Mobile number already registered!");
      return false;
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      firstName: userData.firstName || '',
      lastName: userData.lastName || '',
      username: userData.username || '',
      email: userData.email || '',
      mobile: userData.mobile || '',
      password: userData.password || '',
      role: 'USER',
      walletBalance: 0,
      referralCode: 'LUCKY' + Math.floor(1000 + Math.random() * 9000),
      referralsCount: 0,
      activeReferrals: 0,
      totalWinnings: 0,
      planReferralStats: {},
      joinDate: new Date().toLocaleDateString()
    };

    setUsers(prev => [...prev, newUser]);
    setUser(newUser);
    setIsLoggedIn(true);
    return true;
  };

  const logout = () => { setIsLoggedIn(false); setUser({} as User); };
  const deleteAccount = (userId: string) => { setUsers(prev => prev.filter(u => u.id !== userId)); if (user.id === userId) logout(); };
  const addTokens = (newTokens: Token[]) => setTokens(prev => [...prev, ...newTokens]);
  const updateBalance = (amount: number) => setUser(prev => ({ ...prev, walletBalance: prev.walletBalance + amount }));
  const updateUserBalance = (userId: string, amount: number) => {
    setUsers(prev => prev.map(u => {
      if (u.id === userId) {
        const updated = { ...u, walletBalance: u.walletBalance + amount };
        if (isLoggedIn && user.id === userId) setUser(updated);
        return updated;
      }
      return u;
    }));
  };

  const addTransaction = (tx: Transaction) => setTransactions(prev => [tx, ...prev]);
  const updateTransactionStatus = (id: string, status: 'APPROVED' | 'REJECTED') => {
    setTransactions(prev => prev.map(tx => {
      if (tx.id === id) {
        if (status === 'APPROVED' && tx.status === 'PENDING') {
          const targetUser = users.find(u => u.username === tx.username);
          if (targetUser) updateUserBalance(targetUser.id, tx.netAmount);
        }
        return { ...tx, status };
      }
      return tx;
    }));
  };

  const addLottery = (plan: LotteryPlan) => setLotteryPlans(prev => [...prev, plan]);
  const updateLottery = (plan: LotteryPlan) => setLotteryPlans(prev => prev.map(p => p.id === plan.id ? plan : p));
  const deleteLottery = (id: string) => setLotteryPlans(prev => prev.filter(p => p.id !== id));
  const addPaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => [...prev, method]);
  const updatePaymentMethod = (method: PaymentMethod) => setPaymentMethods(prev => prev.map(m => m.id === method.id ? method : m));
  const deletePaymentMethod = (id: string) => setPaymentMethods(prev => prev.filter(m => m.id !== id));
  const updateWhatsappContact = (link: string) => setWhatsappContact(link);

  return (
    <UserContext.Provider value={{ 
      user, users, isLoggedIn, tokens, transactions, lotteryPlans, paymentMethods, whatsappContact,
      login, signUp, logout, deleteAccount, addTokens, updateBalance, updateUserBalance, addTransaction, 
      updateTransactionStatus, addLottery, updateLottery, deleteLottery, addPaymentMethod, updatePaymentMethod, 
      deletePaymentMethod, updateWhatsappContact
    }}>
      <Router>
        <AppContent />
      </Router>
    </UserContext.Provider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Mail, Lock, Eye, EyeOff, User as UserIcon, Phone, Share2, ArrowRight, Star, Sparkles, UserCircle } from 'lucide-react';
import { useUser } from '../context/UserContext';

const SignUpPage: React.FC = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const location = useLocation();
  const { signUp } = useUser();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    username: '',
    email: '',
    mobile: '',
    password: '',
    confirmPassword: '',
    refCode: ''
  });

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const ref = params.get('ref');
    if (ref) setFormData(prev => ({ ...prev, refCode: ref }));
  }, [location]);

  const handleSignUp = (e: React.FormEvent) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      alert("Passwords do not match!");
      return;
    }

    setLoading(true);

    setTimeout(() => {
      const success = signUp({
        firstName: formData.firstName,
        lastName: formData.lastName,
        username: formData.username,
        email: formData.email,
        mobile: formData.mobile,
        password: formData.password
      });

      setLoading(false);
      if (success) {
        navigate('/wallet');
      }
    }, 800);
  };

  return (
    <div className="min-h-screen flex items-stretch bg-white">
      <div className="hidden lg:flex lg:w-[40%] bg-[#0f172a] relative overflow-hidden flex-col justify-center p-20 text-white">
        <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-emerald-600/10 to-indigo-600/10"></div>
        <div className="relative z-10 max-w-md">
          <div className="inline-flex items-center space-x-2 px-3 py-1 rounded-full bg-white/5 border border-white/10 text-emerald-300 text-[10px] font-black uppercase tracking-[0.2em] mb-8">
            <Star size={12} fill="currentColor" />
            <span>Real-time Registration</span>
          </div>
          <h1 className="text-6xl font-black mb-8 leading-[0.9] tracking-tighter uppercase">Join & <br /><span className="text-emerald-400">Win Real.</span></h1>
          <p className="text-white/60 text-lg font-medium">Register your account to start participating in the biggest weekly draws.</p>
        </div>
      </div>

      <div className="w-full lg:w-[60%] flex items-center justify-center p-6 md:p-20 overflow-y-auto">
        <div className="w-full max-w-2xl space-y-10 py-10 animate-in fade-in slide-in-from-right-10 duration-700">
          <div className="text-center lg:text-left">
            <h2 className="text-4xl font-black text-[#1a233a] mb-2 uppercase tracking-tight">Create Account</h2>
            <p className="text-slate-500 font-medium text-lg">"Join the club of lucky winners!"</p>
          </div>

          <form onSubmit={handleSignUp} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <input required type="text" placeholder="First Name" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-emerald-600 outline-none font-bold bg-slate-50/50" value={formData.firstName} onChange={e => setFormData({...formData, firstName: e.target.value})} />
              <input required type="text" placeholder="Last Name" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-emerald-600 outline-none font-bold bg-slate-50/50" value={formData.lastName} onChange={e => setFormData({...formData, lastName: e.target.value})} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <input required type="text" placeholder="Choose Username" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-indigo-600 outline-none font-bold bg-slate-50/50" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value.toLowerCase()})} />
              <input type="text" placeholder="Referral Code (Optional)" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-indigo-600 outline-none font-black text-xs uppercase tracking-widest bg-slate-50/50" value={formData.refCode} onChange={e => setFormData({...formData, refCode: e.target.value})} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <input required type="email" placeholder="Email Address" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-emerald-600 outline-none font-bold bg-slate-50/50" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
              <input required type="tel" placeholder="Mobile 03XXXXXXXXX" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-emerald-600 outline-none font-bold bg-slate-50/50" value={formData.mobile} onChange={e => setFormData({...formData, mobile: e.target.value})} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="relative group">
                <input required type={showPassword ? 'text' : 'password'} placeholder="Create Password" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-indigo-600 outline-none font-bold bg-slate-50/50" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-600">{showPassword ? <EyeOff size={18} /> : <Eye size={18} />}</button>
              </div>
              <input required type={showPassword ? 'text' : 'password'} placeholder="Confirm Password" className="w-full px-6 py-5 rounded-3xl border-2 border-slate-50 focus:border-indigo-600 outline-none font-bold bg-slate-50/50" value={formData.confirmPassword} onChange={e => setFormData({...formData, confirmPassword: e.target.value})} />
            </div>

            <button disabled={loading} type="submit" className="w-full py-6 bg-[#1a233a] hover:bg-slate-800 text-white font-black rounded-[2rem] shadow-2xl transition-all active:scale-95 flex items-center justify-center space-x-2 uppercase tracking-[0.2em] text-sm disabled:opacity-50">
              {loading ? <span>Processing...</span> : (
                <>
                  <span>Create Account</span>
                  <ArrowRight size={18} />
                </>
              )}
            </button>
          </form>

          <div className="pt-6 text-center lg:text-left border-t border-slate-100">
            <p className="text-slate-500 font-medium">Already a member? <Link to="/login" className="text-emerald-600 font-black hover:underline ml-1">Sign In</Link></p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SignUpPage;

