        // Only attempt to set defaults if user is Admin, as regular users can't write to settings usually
        if (user.role === 'ADMIN') {
          setDoc(doc(db, 'settings', 'global'), { whatsapp: '923177730425' }).catch(() => {});
        }
      }
    }, (err) => console.debug("Settings access pending auth...")));

    // Payment Methods
    unsubs.push(onSnapshot(collection(db, 'paymentMethods'), (snap) => {
      if (!snap.empty) {
        setPaymentMethods(snap.docs.map(d => d.data() as PaymentMethod));
      } else if (user.role === 'ADMIN') {
        const defaults = [
          { id: '1', name: 'EasyPaisa', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' },
          { id: '2', name: 'JazzCash', title: 'Admin Account', number: '03177730425', status: 'ACTIVE', type: 'Mobile Wallet' }
        ];
        defaults.forEach(d => setDoc(doc(db, 'paymentMethods', d.id), d).catch(() => {}));
      }
    }, (err) => console.debug("Payment Methods access pending auth...")));

    // Transactions
    unsubs.push(onSnapshot(query(collection(db, 'transactions'), orderBy('date', 'desc')), (snap) => {
      setTransactions(snap.docs.map(d => ({ ...d.data(), id: d.id } as Transaction)));
    }, (err) => console.debug("Transactions access pending auth...")));

    // Tokens
    unsubs.push(onSnapshot(collection(db, 'tokens'), (snap) => {
      setTokens(snap.docs.map(d => ({ ...d.data(), id: d.id } as any as Token)));
    }, (err) => console.debug("Tokens access pending auth...")));

    // ADMIN ONLY LISTENERS
    if (user.role === 'ADMIN') {
      unsubs.push(onSnapshot(collection(db, 'users'), (snap) => {
        setUsers(snap.docs.map(d => ({ ...d.data(), id: d.id } as User)));
      }, (err) => console.error("Admin: Users listener permission denied")));
    }

    return () => unsubs.forEach(unsub => unsub());
  }, [isLoggedIn, user.role, user.id]);

  const login = async (email?: string, password?: string) => {
