### ⚠️ IMPORTANT: Firebase Security Rules Update
To finalize the fix, you **must** update your Firebase Firestore rules. Go to your **Firebase Console** > **Firestore Database** > **Rules** and paste this:

```javascript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Function to check if the current user is an admin
    function isAdmin() {
      return request.auth != null && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'ADMIN';
    }

    // Users Collection
    match /users/{userId} {
      // Allow user to read/write their own profile
      allow read, write: if request.auth != null && request.auth.uid == userId;
      // Allow Admin to see all users
      allow read, write: if isAdmin();
    }

    // Tokens Collection
    match /tokens/{tokenId} {
      // Allow read for everyone (so we can count sold spots on home page)
      // Or restrict to: if request.auth != null;
      allow read: if true; 
      // Allow user to write their own token (username check)
      allow create: if request.auth != null;
      // Allow Admin full control
      allow update, delete: if isAdmin();
    }

    // Transactions Collection
    match /transactions/{txId} {
      // Allow user to read their own transactions
      allow read: if request.auth != null && resource.data.username == get(/databases/$(database)/documents/users/$(request.auth.uid)).data.username;
      // Allow user to create a request
      allow create: if request.auth != null;
      // Allow Admin to read/write everything
      allow read, write: if isAdmin();
    }

    // Settings Collection
    match /settings/{docId} {
      allow read: if true; // Publicly accessible
      allow write: if isAdmin();
    }

    // Payment Methods
    match /paymentMethods/{methodId} {
      allow read: if true; // Publicly accessible
      allow write: if isAdmin();
    }
  }
}
```

Once you publish these rules, your registration and data synchronization will start working perfectly!

