                               <div>
                                  <span className="block font-black text-slate-900 text-xs uppercase">{log.user}</span>
                                  <span className="text-[9px] text-indigo-600 font-black uppercase tracking-widest">@{log.username}</span>
                               </div>
                            </div>
                         </td>
                         <td className="py-6 px-6">
                            <span className="font-black text-slate-600 text-[10px] uppercase tracking-widest">{log.plan}</span>
                         </td>
                         <td className="py-6 px-6 text-center">
                            <div className="inline-flex items-center space-x-1.5 text-emerald-600 font-black text-[10px] uppercase tracking-widest bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
                               <CheckCircle2 size={12} />
                               <span>{log.goal} Friends</span>
                            </div>
                         </td>
                         <td className="py-6 px-10 text-right">
                            <span className="bg-[#1a233a] text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg">
                               {log.totalEarned} Tokens Won
                            </span>
                         </td>
                      </tr>
                   ))}
                   {rewardLogs.length === 0 && (
                     <tr>
                        <td colSpan={4} className="py-20 text-center text-slate-300 font-black uppercase text-xs">No users reached referral goals yet</td>
                     </tr>
                   )}
                </tbody>
             </table>
          </div>
      </div>
    </div>
  );
};

export default AdminReferrals;

