import React, { useState, useMemo } from 'react';
import { Share2, Users, Gift, TrendingUp, Search, Filter, ArrowUpRight, CheckCircle2, Clock, ShieldCheck, Zap, Edit3, Save, X, ToggleLeft, ToggleRight, Info, ChevronRight, User as UserIcon } from 'lucide-react';
import { useUser } from '../../context/UserContext.ts';

const AdminReferrals: React.FC = () => {
  const { users, lotteryPlans, updateLottery } = useUser();
  const [editingPlanId, setEditingPlanId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState({ threshold: 0, reward: 0 });

  // 1. Calculate Real-time Statistics from actual users
  const stats = useMemo(() => {
    const activePolicies = lotteryPlans.filter(p => p.isReferralEnabled).length;
    const totalReferrers = users.filter(u => u.referralsCount > 0).length;

    // Calculate total free tokens rewarded across all users
    const totalFreeTokens = users.reduce((acc, u) => {
      let count = 0;
      Object.entries(u.planReferralStats || {}).forEach(([planId, refCount]) => {
        const plan = lotteryPlans.find(p => p.id === planId);
        if (plan && plan.isReferralEnabled && plan.referralThreshold > 0) {
          count += Math.floor((refCount as number) / plan.referralThreshold) * plan.referralRewardCount;
        }
      });
      return acc + count;
    }, 0);

    const convRate = users.length > 0 ? Math.round((totalReferrers / users.length) * 100) : 0;

    return [
      { label: 'Active Policies', value: activePolicies.toString(), icon: <Zap size={18} />, color: 'bg-indigo-600' },
      { label: 'Total Referrers', value: totalReferrers.toString(), icon: <Users size={18} />, color: 'bg-emerald-600' },
      { label: 'Free Tokens', value: totalFreeTokens.toString(), icon: <Gift size={18} />, color: 'bg-amber-600' },
      { label: 'Conv. Rate', value: `${convRate}%`, icon: <TrendingUp size={18} />, color: 'bg-pink-600' },
    ];
  }, [users, lotteryPlans]);

  // 2. Generate real-time Reward Trigger Log
  const rewardLogs = useMemo(() => {
    const logs: any[] = [];
    users.forEach(u => {
      Object.entries(u.planReferralStats || {}).forEach(([planId, refCount]) => {
        const plan = lotteryPlans.find(p => p.id === planId);
        if (plan && (refCount as number) > 0) {
          const cycles = Math.floor((refCount as number) / plan.referralThreshold);
          if (cycles > 0) {
            logs.push({
              user: u.firstName + ' ' + u.lastName,
              username: u.username,
              plan: plan.name,
              goal: `${refCount}/${plan.referralThreshold}`,
              date: u.joinDate || 'Recent',
              status: 'CREDITED',
              totalEarned: cycles * plan.referralRewardCount
            });
          }
        }
      });
    });
    return logs.sort((a, b) => b.totalEarned - a.totalEarned).slice(0, 10);
  }, [users, lotteryPlans]);

  const handleStartEdit = (plan: any) => {
    setEditingPlanId(plan.id);
    setEditValues({ threshold: plan.referralThreshold, reward: plan.referralRewardCount });
  };

  const handleSave = (plan: any) => {
    updateLottery({
      ...plan,
      referralThreshold: editValues.threshold,
      referralRewardCount: editValues.reward
    });
    setEditingPlanId(null);
  };

  const togglePlanReferral = (plan: any) => {
    updateLottery({
      ...plan,
      isReferralEnabled: !plan.isReferralEnabled
    });
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-16">

      {/* 1. RESPONSIVE HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 px-1">
        <div>
          <h1 className="text-2xl md:text-4xl font-black text-slate-900 uppercase tracking-tight leading-none">Referral Policies</h1>
          <p className="text-[10px] md:text-sm text-slate-500 font-bold uppercase tracking-widest mt-2">Manage automated rewards</p>
        </div>
        <div className="w-full md:w-auto">
           <div className="bg-emerald-50 text-emerald-600 px-4 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest border border-emerald-100 flex items-center justify-center space-x-2">
              <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
              <span>Real-Time Engine Active</span>
           </div>
        </div>
      </div>

      {/* 2. STATS GRID */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white rounded-2xl md:rounded-[2.5rem] p-4 md:p-8 border border-slate-100 shadow-sm flex flex-col items-center md:items-start text-center md:text-left group transition-all hover:shadow-md">
             <div className={`${stat.color} w-10 h-10 md:w-14 md:h-14 rounded-xl md:rounded-2xl flex items-center justify-center text-white mb-3 md:mb-6 shadow-lg shadow-indigo-500/10 group-hover:scale-110 transition-transform`}>
                {stat.icon}
             </div>
             <span className="block text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1 md:mb-2">{stat.label}</span>
             <h3 className="text-lg md:text-3xl font-black text-slate-900 leading-none">{stat.value}</h3>
          </div>
        ))}
      </div>

      {/* 3. DYNAMIC POLICY CONFIGURATION GRID */}
      <section className="bg-white rounded-[2rem] md:rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
         <div className="p-6 md:p-10 border-b border-slate-50 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-slate-50/30">
            <div>
               <h3 className="font-black text-slate-900 uppercase tracking-tight flex items-center space-x-2 text-xs md:text-lg">
                 <ShieldCheck className="text-indigo-600" size={18} />
                 <span>Logic Configuration Grid</span>
               </h3>
               <p className="text-[9px] md:text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Customize rewards per category</p>
            </div>
         </div>

         <div className="p-4 md:p-10">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-8">
               {lotteryPlans.map((plan) => (
                  <div key={plan.id} className={`p-6 md:p-8 rounded-[1.5rem] md:rounded-[2.5rem] border-2 transition-all relative ${plan.isReferralEnabled ? 'bg-white border-slate-100 hover:border-indigo-100 shadow-sm' : 'bg-slate-50 border-dashed border-slate-200 opacity-60 grayscale-[0.5]'}`}>

                     <div className="flex justify-between items-start mb-6 md:mb-8">
                        <div className="flex items-center space-x-3 md:space-x-4 min-w-0">
                           <span className="text-3xl md:text-5xl group-hover:scale-110 transition-transform flex-shrink-0">{plan.icon}</span>
                           <div className="min-w-0">
                              <span className="block font-black text-slate-900 text-[11px] md:text-sm uppercase truncate">{plan.name}</span>
                              <span className={`text-[8px] md:text-[9px] font-black uppercase tracking-widest truncate block ${plan.isReferralEnabled ? 'text-indigo-600' : 'text-slate-400'}`}>
                                 {plan.isReferralEnabled ? 'Active' : 'Paused'}
                              </span>
                           </div>
                        </div>
                        <div className="flex items-center space-x-1 flex-shrink-0">
                           <button onClick={() => togglePlanReferral(plan)} className="transition-all transform scale-90 md:scale-100">
                              {plan.isReferralEnabled ? <ToggleRight className="text-emerald-500" size={32} /> : <ToggleLeft className="text-slate-300" size={32} />}
                           </button>
                           {plan.isReferralEnabled && !editingPlanId && (
                             <button onClick={() => handleStartEdit(plan)} className="p-2 text-slate-400 hover:text-indigo-600 transition-all">
                                <Edit3 size={16} />
                             </button>
                           )}
                        </div>
                     </div>

                     {plan.isReferralEnabled ? (
                       <div className="space-y-4">
                          {editingPlanId === plan.id ? (
                            <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                               <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                                  <div className="space-y-1.5">
                                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block">Invites Goal</label>
                                    <input 
                                      type="number" 
                                      className="w-full px-3 py-3 bg-slate-50 border border-indigo-100 rounded-xl text-xs font-black text-indigo-600 outline-none focus:ring-2 focus:ring-indigo-600/5 transition-all"
                                      value={editValues.threshold}
                                      onChange={(e) => setEditValues({...editValues, threshold: Number(e.target.value)})}
                                    />
                                  </div>
                                  <div className="space-y-1.5">
                                    <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block">Free Tokens</label>
                                    <input 
                                      type="number" 
                                      className="w-full px-3 py-3 bg-slate-50 border border-indigo-100 rounded-xl text-xs font-black text-emerald-600 outline-none focus:ring-2 focus:ring-indigo-600/5 transition-all"
                                      value={editValues.reward}
                                      onChange={(e) => setEditValues({...editValues, reward: Number(e.target.value)})}
                                    />
                                  </div>
                               </div>
                               <div className="flex space-x-2 pt-1">
                                  <button onClick={() => handleSave(plan)} className="flex-grow py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Update</button>
                                  <button onClick={() => setEditingPlanId(null)} className="px-4 py-3 bg-slate-100 text-slate-500 rounded-xl text-[9px] font-black uppercase">X</button>
                               </div>
                            </div>
                          ) : (
                            <div className="space-y-3">
                               <div className="flex justify-between items-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Milestone</span>
                                  <span className="text-sm font-black text-slate-900">{plan.referralThreshold} Invites</span>
                               </div>
                               <div className="flex justify-between items-center bg-slate-50/50 p-4 rounded-2xl border border-slate-50">
                                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Free Reward</span>
                                  <span className="text-sm font-black text-emerald-600">{plan.referralRewardCount} Tokens</span>
                               </div>
                            </div>
                          )}
                       </div>
                     ) : (
                       <div className="py-6 text-center flex flex-col items-center justify-center bg-slate-50/50 rounded-2xl border border-dashed border-slate-100">
                          <ShieldCheck size={24} className="text-slate-200 mb-2" />
                          <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">Policy Inactive</p>
                       </div>
                     )}
                  </div>
               ))}
            </div>
         </div>
      </section>

      {/* 4. REAL-TIME ACTIVITY LOG */}
      <div className="bg-white rounded-[2rem] md:rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 md:p-10 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
             <h3 className="font-black text-slate-900 uppercase tracking-tight text-xs md:text-base">Real-time Reward Milestones</h3>
             <span className="hidden sm:inline-block text-[10px] font-black text-indigo-600 uppercase tracking-widest border border-indigo-100 px-3 py-1 rounded-full">System Ledger</span>
          </div>

          <div className="overflow-x-auto">
             <table className="w-full text-left min-w-[650px]">
                <thead>
                   <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                      <th className="py-6 px-10">Referrer Profile</th>
                      <th className="py-6 px-6">Trigger Plan</th>
                      <th className="py-6 px-6 text-center">Progress Stat</th>
                      <th className="py-6 px-10 text-right">Free Tokens</th>
                   </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                   {rewardLogs.map((log, i) => (
                      <tr key={i} className="hover:bg-slate-50/30 transition-colors">
                         <td className="py-6 px-10">
                            <div className="flex items-center space-x-3">
                               <div className="w-9 h-9 bg-indigo-600 text-white rounded-xl flex items-center justify-center font-black text-[11px] uppercase border-2 border-white shadow-md">{log.user.charAt(0)}</div>
                               <div className="min-w-0">
                                  <span className="block font-black text-slate-900 text-xs uppercase truncate max-w-[120px]">{log.user}</span>
                                  <span className="text-[9px] text-indigo-600 font-black uppercase tracking-widest">@{log.username}</span>
                               </div>
                            </div>
                         </td>
                         <td className="py-6 px-6">
                            <span className="font-black text-slate-600 text-[10px] uppercase tracking-widest">{log.plan}</span>
                         </td>
                         <td className="py-6 px-6 text-center">
                            <div className="inline-flex items-center space-x-1.5 text-emerald-600 font-black text-[9px] uppercase tracking-widest bg-emerald-50 px-3 py-1.5 rounded-full border border-emerald-100">
                               <CheckCircle2 size={10} />
                               <span>{log.goal} Done</span>
                            </div>
                         </td>
                         <td className="py-6 px-10 text-right">
                            <span className="bg-[#1a233a] text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">
                               {log.totalEarned} Tokens Won
                            </span>
                         </td>
                      </tr>
                   ))}
                   {rewardLogs.length === 0 && (
                     <tr>
                        <td colSpan={4} className="py-20 text-center text-slate-300 font-black uppercase text-[10px] tracking-widest">No referral milestones recorded yet</td>
                     </tr>
                   )}
                </tbody>
             </table>
          </div>
      </div>
    </div>
  );
};

