import React, { useState, useMemo } from 'react';
import { Share2, Users, Gift, TrendingUp, Search, Filter, ArrowUpRight, CheckCircle2, Clock, ShieldCheck, Zap, Edit3, Save, X, ToggleLeft, ToggleRight, Info, ChevronRight, User as UserIcon } from 'lucide-react';
import { useUser } from '../../context/UserContext.ts';

const AdminReferrals: React.FC = () => {
  const { users, lotteryPlans, updateLottery } = useUser();
  const [editingPlanId, setEditingPlanId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState({ threshold: 0, reward: 0 });

  // 1. Calculate Real-time Statistics
  const stats = useMemo(() => {
    const activePolicies = lotteryPlans.filter(p => p.isReferralEnabled).length;
    const totalReferrers = users.filter(u => u.referralsCount > 0).length;

    const totalFreeTokens = users.reduce((acc, u) => {
      let count = 0;
      Object.entries(u.planReferralStats || {}).forEach(([planId, refCount]) => {
        const plan = lotteryPlans.find(p => p.id === planId);
        if (plan && plan.isReferralEnabled && plan.referralThreshold > 0) {
          count += Math.floor((refCount as number) / plan.referralThreshold) * plan.referralRewardCount;
        }
      });
      return acc + count;
    }, 0);

    const convRate = users.length > 0 ? Math.round((totalReferrers / users.length) * 100) : 0;

    return [
      { label: 'Policies', value: activePolicies.toString(), icon: <Zap size={16} />, color: 'bg-indigo-600' },
      { label: 'Referrers', value: totalReferrers.toString(), icon: <Users size={16} />, color: 'bg-emerald-600' },
      { label: 'Free Tkn', value: totalFreeTokens.toString(), icon: <Gift size={16} />, color: 'bg-amber-600' },
      { label: 'Conv.', value: `${convRate}%`, icon: <TrendingUp size={16} />, color: 'bg-pink-600' },
    ];
  }, [users, lotteryPlans]);

  // 2. Reward Trigger Log
  const rewardLogs = useMemo(() => {
    const logs: any[] = [];
    users.forEach(u => {
      Object.entries(u.planReferralStats || {}).forEach(([planId, refCount]) => {
        const plan = lotteryPlans.find(p => p.id === planId);
        if (plan && (refCount as number) > 0) {
          const cycles = Math.floor((refCount as number) / plan.referralThreshold);
          if (cycles > 0) {
            logs.push({
              user: u.firstName + ' ' + u.lastName,
              username: u.username,
              plan: plan.name,
              goal: `${refCount}/${plan.referralThreshold}`,
              date: u.joinDate || 'Recent',
              status: 'CREDITED',
              totalEarned: cycles * plan.referralRewardCount
            });
          }
        }
      });
    });
    return logs.sort((a, b) => b.totalEarned - a.totalEarned).slice(0, 10);
  }, [users, lotteryPlans]);

  const handleStartEdit = (plan: any) => {
    setEditingPlanId(plan.id);
    setEditValues({ threshold: plan.referralThreshold, reward: plan.referralRewardCount });
  };

  const handleSave = (plan: any) => {
    updateLottery({
      ...plan,
      referralThreshold: editValues.threshold,
      referralRewardCount: editValues.reward
    });
    setEditingPlanId(null);
  };

  const togglePlanReferral = (plan: any) => {
    updateLottery({
      ...plan,
      isReferralEnabled: !plan.isReferralEnabled
    });
  };

  return (
    <div className="space-y-4 md:space-y-10 animate-in fade-in duration-500 pb-20 max-w-full overflow-hidden">

      {/* 1. RESPONSIVE HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-3 px-1">
        <div className="min-w-0 flex-1">
          <h1 className="text-xl md:text-4xl font-black text-slate-900 uppercase tracking-tight leading-none truncate">Referral Policies</h1>
          <p className="text-[9px] md:text-sm text-slate-500 font-bold uppercase tracking-widest mt-1 truncate">Manage Rewards Logic</p>
        </div>
        <div className="w-auto">
           <div className="bg-emerald-50 text-emerald-600 px-3 py-1.5 rounded-lg text-[8px] md:text-[10px] font-black uppercase tracking-widest border border-emerald-100 flex items-center space-x-1.5 shadow-sm">
              <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
              <span className="whitespace-nowrap">Engine Live</span>
           </div>
        </div>
      </div>

      {/* 2. STATS GRID - 2 columns on small mobile */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 md:gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white rounded-xl md:rounded-[2.5rem] p-3 md:p-8 border border-slate-100 shadow-sm flex items-center md:items-start space-x-3 md:space-x-0 md:flex-col group hover:shadow-md transition-all">
             <div className={`${stat.color} w-8 h-8 md:w-14 md:h-14 rounded-lg md:rounded-2xl flex items-center justify-center text-white flex-shrink-0 shadow-md`}>
                <div className="scale-90 md:scale-100">{stat.icon}</div>
             </div>
             <div className="min-w-0 md:mt-6">
                <span className="block text-[7px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-0.5 md:mb-2 truncate">{stat.label}</span>
                <h3 className="text-sm md:text-3xl font-black text-slate-900 leading-none truncate">{stat.value}</h3>
             </div>
          </div>
        ))}
      </div>

      {/* 3. DYNAMIC POLICY CONFIGURATION GRID */}
      <section className="bg-white rounded-[1.25rem] md:rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
         <div className="p-4 md:p-10 border-b border-slate-50 flex flex-col md:flex-row justify-between items-start md:items-center gap-2 bg-slate-50/30">
            <div className="min-w-0">
               <h3 className="font-black text-slate-900 uppercase tracking-tight flex items-center space-x-2 text-[10px] md:text-lg">
                 <ShieldCheck className="text-indigo-600 flex-shrink-0" size={14} />
                 <span className="truncate">Logic Configuration</span>
               </h3>
               <p className="text-[7px] md:text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-0.5 truncate">Customize per category</p>
            </div>
         </div>

         <div className="p-3 md:p-10">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 md:gap-8">
               {lotteryPlans.map((plan) => (
                  <div key={plan.id} className={`p-4 md:p-8 rounded-2xl md:rounded-[2.5rem] border-2 transition-all relative overflow-hidden ${plan.isReferralEnabled ? 'bg-white border-slate-100 hover:border-indigo-100 shadow-sm' : 'bg-slate-50 border-dashed border-slate-200 opacity-60 grayscale-[0.5]'}`}>

                     <div className="flex justify-between items-start mb-4 md:mb-8">
                        <div className="flex items-center space-x-2 md:space-x-4 min-w-0">
                           <span className="text-xl md:text-5xl group-hover:scale-110 transition-transform flex-shrink-0">{plan.icon}</span>
                           <div className="min-w-0">
                              <span className="block font-black text-slate-900 text-[10px] md:text-sm uppercase truncate max-w-[120px] md:max-w-none">{plan.name}</span>
                              <span className={`text-[7px] md:text-[9px] font-black uppercase tracking-widest truncate block ${plan.isReferralEnabled ? 'text-indigo-600' : 'text-slate-400'}`}>
                                 {plan.isReferralEnabled ? 'Active' : 'Paused'}
                              </span>
                           </div>
                        </div>
                        <div className="flex items-center space-x-1 flex-shrink-0">
                           <button onClick={() => togglePlanReferral(plan)} className="transition-all transform scale-75 md:scale-100">
                              {plan.isReferralEnabled ? <ToggleRight className="text-emerald-500" size={28} /> : <ToggleLeft className="text-slate-300" size={28} />}
                           </button>
                           {plan.isReferralEnabled && !editingPlanId && (
                             <button onClick={() => handleStartEdit(plan)} className="p-1 text-slate-400 hover:text-indigo-600 transition-all">
                                <Edit3 size={14} />
                             </button>
                           )}
                        </div>
                     </div>

                     {plan.isReferralEnabled ? (
                       <div className="space-y-3">
                          {editingPlanId === plan.id ? (
                            <div className="space-y-2 animate-in fade-in slide-in-from-top-1">
                               <div className="grid grid-cols-1 gap-2">
                                  <div className="space-y-1">
                                    <label className="text-[7px] font-black text-slate-400 uppercase tracking-widest block">Goal (Invites)</label>
                                    <input 
                                      type="number" 
                                      className="w-full px-3 py-2 bg-slate-50 border border-indigo-100 rounded-lg text-[10px] font-black text-indigo-600 outline-none"
                                      value={editValues.threshold}
                                      onChange={(e) => setEditValues({...editValues, threshold: Number(e.target.value)})}
                                    />
                                  </div>
                                  <div className="space-y-1">
                                    <label className="text-[7px] font-black text-slate-400 uppercase tracking-widest block">Free Reward</label>
                                    <input 
                                      type="number" 
                                      className="w-full px-3 py-2 bg-slate-50 border border-indigo-100 rounded-lg text-[10px] font-black text-emerald-600 outline-none"
                                      value={editValues.reward}
                                      onChange={(e) => setEditValues({...editValues, reward: Number(e.target.value)})}
                                    />
                                  </div>
                               </div>
                               <div className="flex space-x-1.5 pt-1">
                                  <button onClick={() => handleSave(plan)} className="flex-grow py-2.5 bg-indigo-600 text-white rounded-lg text-[8px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Apply</button>
                                  <button onClick={() => setEditingPlanId(null)} className="px-3 py-2.5 bg-slate-100 text-slate-500 rounded-lg text-[8px] font-black uppercase">Cancel</button>
                               </div>
                            </div>
                          ) : (
                            <div className="grid grid-cols-1 gap-2">
                               <div className="flex justify-between items-center bg-slate-50/50 p-2.5 rounded-xl border border-slate-50">
                                  <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Goal</span>
                                  <span className="text-[10px] md:text-[11px] font-black text-slate-900">{plan.referralThreshold} Invites</span>
                               </div>
                               <div className="flex justify-between items-center bg-slate-50/50 p-2.5 rounded-xl border border-slate-50">
                                  <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Earn</span>
                                  <span className="text-[10px] md:text-[11px] font-black text-emerald-600">{plan.referralRewardCount} Token</span>
