                          <p className="text-[7px] font-black text-slate-300 uppercase tracking-widest">Policy Inactive</p>
                       </div>
                     )}
                  </div>
               ))}
            </div>
         </div>
      </section>

      {/* 4. REAL-TIME ACTIVITY LOG - Better Scroll handling */}
      <div className="bg-white rounded-[1.25rem] md:rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-4 md:p-10 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
             <h3 className="font-black text-slate-900 uppercase tracking-tight text-[10px] md:text-base truncate mr-2">Reward Milestones Log</h3>
             <span className="flex-shrink-0 text-[8px] md:text-[10px] font-black text-indigo-600 uppercase tracking-widest border border-indigo-100 px-2 py-1 rounded-full whitespace-nowrap">System Ledger</span>
